// Consolidar análisis de todos los agentes
const datosOriginal = $('Recibir Caso').first().json;

let agentes = {
  triage: { area: 'media', complejidad: 'media', urgencia: 'media', equipos: [], resumen: '' },
  hardware: { detectado: false, componentes: [], acciones: [], tiempo: 30 },
  software: { detectado: false, so: '', apps: [], tipo_error: '', tiempo: 30 },
  redes: { detectado: false, tipo_conexion: '', equipos: [], tiempo: 20 },
  seguridad: { detectado: false, amenaza: '', critico: 'bajo', tiempo: 45 }
};

// Procesar cada agente
const nodos = $input.all();
nodos.forEach(nodo => {
  const nombre = nodo.json.nombre || '';
  if (nombre.includes('Triaje')) {
    try { agentes.triage = JSON.parse(nodo.json.texto); } catch(e) {}
  } else if (nombre.includes('Hardware')) {
    try { agentes.hardware = JSON.parse(nodo.json.texto); } catch(e) {}
  } else if (nombre.includes('Software')) {
    try { agentes.software = JSON.parse(nodo.json.texto); } catch(e) {}
  } else if (nombre.includes('Redes')) {
    try { agentes.redes = JSON.parse(nodo.json.texto); } catch(e) {}
  } else if (nombre.includes('Seguridad')) {
    try { agentes.seguridad = JSON.parse(nodo.json.texto); } catch(e) {}
  }
});

// Determinar diagnóstico final
const areasDetectadas = [];
if (agentes.hardware.hardware) areasDetectadas.push('Hardware');
if (agentes.software.software) areasDetectadas.push('Software');
if (agentes.redes.redes) areasDetectadas.push('Redes');
if (agentes.seguridad.seguridad) areasDetectadas.push('Seguridad');

// Calcular urgencia máxima
const urgencias = [agentes.triage.urgencia];
if (agentes.seguridad.nivel_critico === 'alto') urgencias.push('alta');
const urgenciaMax = urgencias.includes('alta') ? 'alta' : (urgencias.includes('media') ? 'media' : 'baja');

// Calcular tiempo total
const tiempoTotal = Math.max(
  agentes.hardware.tiempo_min || 30,
  agentes.software.tiempo_min || 30,
  agentes.redes.tiempo_min || 20,
  agentes.seguridad.tiempo_min || 45
);

return {
  json: {
    ...datosOriginal,
    agentes,
    areasDetectadas: areasDetectadas.join(', '),
    urgencia: urgenciaMax,
    duracion: tiempoTotal,
    estado: 'diagnostico_listo',
    requiere_multiple_agentes: areasDetectadas.length > 1,
    necesita_visita: agentes.hardware.hardware || urgenciaMax === 'alta'
  }
};

// Preparar datos para agendamiento
const datos = $input.first().json;

// Extraer diagnóstico de síntesis
let diag = { principal: '', areas: [], causa: '', solucion: '', duracion: 30, urgencia: 'media', visita: false };

try {
  if (datos.sintesis?.candidates?.[0]?.content?.parts[0]?.text) {
    const texto = datos.sintesis.candidates[0].content.parts[0].text;
    const match = texto.match(/\{[\s\S]*\}/);
    if (match) diag = JSON.parse(match[0]);
  }
} catch (e) {}

// Calcular horarios (9 AM - 5 PM)
const ahora = new Date();
const opciones = [];
const horas = [9, 10, 11, 12, 13, 14, 15, 16];

for (let h of horas) {
  const opt = new Date(ahora);
  opt.setHours(h, 0, 0, 0);
  if (opt > ahora && opciones.length < 3) opciones.push(opt.toISOString());
}

// Si es tarde (después de las 5 PM), agregar opciones para mañana
if (opciones.length < 3) {
  const manana = new Date(ahora);
  manana.setDate(manana.getDate() + 1);
  const mananaHoras = [9, 10, 11];
  for (let h of mananaHoras) {
    if (opciones.length >= 3) break;
    const opt = new Date(manana);
    opt.setHours(h, 0, 0, 0);
    opciones.push(opt.toISOString());
  }
}

const duracion = diag.duracion || datos.duracion || 30;
const fechaSugerida = opciones[0];
const fechaFin = new Date(new Date(fechaSugerida).getTime() + duracion * 60000);

const emojiUrgencia = diag.urgencia === 'alta' ? '🔴' : (diag.urgencia === 'baja' ? '🟢' : '🟡');

return {
  json: {
    ...datos,
    diagnosticoFinal: diag,
    fechaSugerida,
    fechaFin: fechaFin.toISOString(),
    duracion,
    urgencia: diag.urgencia || datos.urgencia,
    emojiUrgencia,
    opcionesHorario: opciones,
    requiere_visita: diag.visita || datos.necesita_visita,
    areas: diag.areas?.join(', ') || datos.areasDetectadas,
    titulo: `SISTEMAS 4A - ${datos.nombre}`,
    descripcion: `${emojiUrgencia} *Diagnóstico del Equipo Técnico*\n\n📋 ${diag.principal || 'Análisis en proceso'}\n\n💡 *Causa:* ${diag.causa || 'Por determinar'}\n\n🔧 *Solución:* ${diag.solucion || 'Por definir'}\n\n⏱️ Duración: ${duracion} min\n📍 ${diag.visita ? 'Requiere Visita Técnica' : 'Consulta Virtual'}`
  }
};
